use std::collections::HashMap;
use std::sync::{Arc, Mutex};

type RateStore = Arc<Mutex<HashMap<String, u32>>>;

fn initialize_rate_store() -> RateStore {
    Arc::new(Mutex::new(HashMap::new()))
}

fn check_and_update_rate(store: &RateStore, user_id: &str) -> bool {
    let mut map = store.lock().unwrap();
    let current_count = map.entry(user_id.to_string()).or_insert(0);

    if *current_count < 10 {
        *current_count += 1;
        true
    } else {
        false
    }
}

fn main() {
    let store = initialize_rate_store();

    println!("Attempting to check rate limit for user A...");
    let result_a1 = check_and_update_rate(&store, "user_A");
    println!("User A request 1 successful: {}", result_a1);

    for i in 2..=10 { 
        let success = check_and_update_rate(&store, "user_A");
        println!("User A request {} successful: {}", i, success);
    }

    println!("
Attempting to check rate limit for user B...");
    let result_b1 = check_and_update_rate(&store, "user_B");
    println!("User B request 1 successful: {}", result_b1);

    if !check_and_update_rate(&store, "user_A") {
        println!("Rate limit hit for user A on this attempt.");
    }
}

use std::collections::HashMap;

struct SourceMapGenerator {
    mapping: HashMap<String, u32>,
}

impl SourceMapGenerator {
    fn new() -> Self {
        SourceMapGenerator { 
            mapping: HashMap::new()
        }
    }

    fn add_source_mapping(&mut self, path: String, line_number: u32) {
        self.mapping.insert(path, line_number);
    }

    fn generate_map(&self, object_paths: Vec<String>) -> HashMap<String, u32> {
        let mut result = HashMap::new();
        for path in object_paths {
            if let Some(&line) = self.mapping.get(&path) {
                result.insert(path, line);
            }
        }
        result
    }
}

fn main() {
    let mut generator = SourceMapGenerator::new();
    generator.add_source_mapping("component.tsx:10".to_string(), 10);
    generator.add_source_mapping("utils/api.ts:50".to_string(), 50);
    generator.add_source_mapping("styles.css:2".to_string(), 2);

    let paths_to_check = vec!["component.tsx:10".to_string(), "utils/api.ts:50".to_string(), "missing_path".to_string()];
    let final_map = generator.generate_map(paths_to_check);

    println!("Generated Source Map: {:?}", final_map);
}

use std::collections::HashMap;
use std::sync::Arc;

struct VectorCache {
    data: Vec<f32>,
    dimensions: usize,
    count: usize,
}

impl VectorCache {
    fn new(data: Vec<f32>, dimensions: usize, count: usize) -> Self {
        VectorCache { data, dimensions, count }
    }

    fn get_vector(&self, index: usize) -> Result<&[f32], &'static str> {
        if index >= self.count {
            return Err("Index out of bounds");
        }
        let start = index * self.dimensions;
        let end = start + self.dimensions;
        Ok(&self.data[start..end])
    }
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let dimensions = 128;
    let num_vectors = 500;
    let mut raw_data: Vec<f32> = Vec::with_capacity(dimensions * num_vectors);

    for i in 0..num_vectors {
        for j in 0..dimensions {
            raw_data.push((i + 1) as f32 * (j + 1) as f32 / 1000.0);
        }
    }

    let cache = Arc::new(VectorCache::new(raw_data, dimensions, num_vectors));

    match cache.get_vector(10) {
        Ok(vec) => println!("Successfully retrieved a vector of size {}", vec.len()),
        Err(e) => eprintln!("Error: {}", e),
    }

    Ok(())
}

use std::alloc::{GlobalAlloc, Layout, System};
use std::ptr;
use std::sync::atomic::{AtomicBool, Ordering};
struct SimpleAllocator {
    allocated: AtomicBool,
}
impl SimpleAllocator {
    fn new() -> Self {
        SimpleAllocator {
            allocated: AtomicBool::new(false),
        }
    }
}
unsafe impl GlobalAlloc for SimpleAllocator {
    unsafe fn alloc(&self, layout: Layout) -> *mut u8 {
        if self.allocated.load(Ordering::Relaxed) {
            ptr::null_mut()
        } else {
            System.alloc(layout)
        }
    }
    unsafe fn dealloc(&self, ptr: *mut u8, layout: Layout) {
        System.dealloc(ptr, layout)
    }
}
fn main() {
    let allocator = SimpleAllocator::new();
    let data_size = 1024 * 10;
    let align = std::mem::align_of::<u32>();
    let layout = Layout::from_size_align(data_size, align).unwrap();
    let ptr = unsafe { allocator.alloc(layout) };
    if ptr.is_null() {
        println!("Failed to allocate memory.");
    } else {
        unsafe {
            std::ptr::write_bytes(ptr, 0, data_size);
            println!("Successfully allocated {} bytes using custom logic.", data_size);
            allocator.allocated.store(true, Ordering::Relaxed);
            let _ = allocator.dealloc(ptr, layout);
        }
    }
}

use std::collections::{HashMap};
use std::sync::{Arc, Mutex};

struct DataProcessor {
    cache: Arc<Mutex<HashMap<String, Vec<i32>>>>
}

impl DataProcessor {
    fn new() -> Self {
        DataProcessor { cache: Arc::new(Mutex::new(HashMap::new())) }
    }

    fn get_or_process(&self, key: String, initial_value: i32) -> i32 {
        let mut cache_guard = self.cache.lock().unwrap();
        if let Some(data) = cache_guard.get(&key) {
            return data[0]
        }

        let processed_result = self.perform_expensive_calculation(&key, initial_value);

        let mut cache_guard_reacquire = self.cache.lock().unwrap();
        cache_guard_reacquire.insert(key, vec![processed_result]);
        processed_result
    }

    fn perform_expensive_calculation(&self, key: &str, offset: i32) -> i32 {
        println!("Simulating expensive block execution for key: {}", key);
        let mut values = vec![offset * 10];
        for i in 0..5 {
            values.push(i)
        }
        values.iter().sum()
    }
}

fn main() {
    let processor = DataProcessor::new();
    let key1 = String::from("user_session_123");
    let offset1: i32 = 5;

    let result1 = processor.get_or_process(key1.clone(), offset1);
    println!("First run result for {}: {}", key1, result1);

    let result2 = processor.get_or_process(key1.clone(), 0);
    println!("Second run result (should hit cache): {}", result2);

    let key2 = String::from("api_endpoint_xyz");
    let offset2: i32 = 1;
    let _ = processor.get_or_process(key2, offset2);
}
